def _to_ws_base_url(raw_url: str) -> str:
    normalized = (raw_url or "").strip()
    if normalized.startswith("https://"):
        return f"wss://{normalized.removeprefix('https://')}"
    if normalized.startswith("http://"):
        return f"ws://{normalized.removeprefix('http://')}"
